#!/bin/bash
# common.sh — sourced by other scripts.
# Loads /etc/s3files-bench.env which contains:
#   BUCKET_A=...
#   BUCKET_B=...
#   S3FILES_FS_ID=fs-...
#   EFS_FS_ID=fs-...
#   AWS_REGION=us-east-1
# This file is generated by `make seed` (or its scripts/00_load_env.sh helper)
# from CloudFormation outputs after deploy.

ENV_FILE=${ENV_FILE:-/etc/s3files-bench.env}
if [[ ! -f "$ENV_FILE" ]]; then
  echo "[common] $ENV_FILE not found. Generate via:" >&2
  echo "  make seed   # populates env from CFN outputs" >&2
  exit 1
fi
# shellcheck disable=SC1090
source "$ENV_FILE"

: "${BUCKET_A:?BUCKET_A unset}"
: "${BUCKET_B:?BUCKET_B unset}"
: "${S3FILES_FS_ID:?S3FILES_FS_ID unset}"
: "${EFS_FS_ID:?EFS_FS_ID unset}"
: "${AWS_REGION:?AWS_REGION unset}"

MOUNT_S3FILES=${MOUNT_S3FILES:-/mnt/s3files}
MOUNT_MOUNTPOINT=${MOUNT_MOUNTPOINT:-/mnt/mountpoint}
MOUNT_EFS=${MOUNT_EFS:-/mnt/efs}
RESULT_DIR=${RESULT_DIR:-$MOUNT_EFS/results}

mkdir -p "$RESULT_DIR"

systems_all=(s3files mountpoint efs)
profiles_all=(p1_shard_seq_read p2_random_read_4k p3_checkpoint_write p4_mixed_train)

mount_dir_for() {
  case "$1" in
    s3files)    echo "$MOUNT_S3FILES" ;;
    mountpoint) echo "$MOUNT_MOUNTPOINT" ;;
    efs)        echo "$MOUNT_EFS" ;;
    *) echo "unknown system: $1" >&2; return 2 ;;
  esac
}
